1	type Item = { type: string; cursed?: boolean };
2	type Scenario = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	const COMPONENT_BASE_PER_ITEM = 25;
6	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	export function runScenario(input: unknown): unknown {
16	  const { steps } = input as Scenario;
17	  const premium = computePremium(steps[0].items);
18	  return { results: [{ premium }] };
19	}
20	
21	function computePremium(items: Item[]): number {
22	  if (items.length === 0) return PROCESSING_FEE;
23	  if (items.every(isComponent)) return componentsPremium(items);
24	  const item = items[0];
25	  const base = BASE_PREMIUM_BY_TYPE[item.type];
26	  const cursed = item.cursed ? base * 0.5 : 0;
27	  const firstInsurance = base * 0.1;
28	  return Math.ceil(base + cursed + firstInsurance) + PROCESSING_FEE;
29	}
30	
31	function componentsPremium(items: Item[]): number {
32	  const runes = items.filter((i) => i.type === "rune").length;
33	  const moonstones = items.filter((i) => i.type === "moonstone").length;
34	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
35	}
36	
37	function componentTypeBase(count: number): number {
38	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
39	}
40	
41	function isComponent(item: Item): boolean {
42	  return item.type === "rune" || item.type === "moonstone";
43	}
44	
45	function premiumFromBase(base: number): number {
46	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
47	}
